        if exc.status_code == 409:
            logging.info("Event type %s already exists", EVENT_TYPE)
            return
        raise


def create_messages(svix: Svix) -> None:
    for i in range(5):
        svix.message.create(
            APP_UID,
            {
                "eventType": EVENT_TYPE,
                "payload": {"test": i},
            },
